package controle.api.back_end.config;

import org.springframework.boot.context.event.ApplicationReadyEvent;
import org.springframework.context.ApplicationListener;
import org.springframework.core.io.ClassPathResource;
import org.springframework.jdbc.datasource.init.ResourceDatabasePopulator;
import org.springframework.stereotype.Component;

import javax.sql.DataSource;

/**
 * Popula as tabelas de referencia (instituicao, categoria) na inicializacao da aplicacao.
 *
 * Executa DEPOIS que o Hibernate ja criou/atualizou as tabelas (ddl-auto=update),
 * garantindo que o script nao falhe por tabelas inexistentes.
 *
 * Usa setContinueOnError(true) para que erros de chave duplicada (INSERT IGNORE)
 * sejam ignorados silenciosamente nas inicializacoes subsequentes.
 */
@Component
public class DataInitializer implements ApplicationListener<ApplicationReadyEvent> {

    private final DataSource dataSource;

    public DataInitializer(DataSource dataSource) {
        this.dataSource = dataSource;
    }

    @Override
    public void onApplicationEvent(ApplicationReadyEvent event) {
        try {
            ResourceDatabasePopulator populator = new ResourceDatabasePopulator();
            populator.addScript(new ClassPathResource("data.sql"));
            populator.setContinueOnError(true);
            populator.setSeparator(";");
            populator.execute(dataSource);
            System.out.println("[DataInitializer] Dados iniciais carregados com sucesso.");
        } catch (Exception e) {
            System.err.println("[DataInitializer] Erro ao carregar dados iniciais: " + e.getMessage());
        }
    }
}

package controle.api.back_end.config;

import ch.vorburger.exec.ManagedProcessException;
import ch.vorburger.mariadb4j.DB;
import ch.vorburger.mariadb4j.DBConfigurationBuilder;
import com.zaxxer.hikari.HikariDataSource;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.boot.autoconfigure.condition.ConditionalOnProperty;
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import org.springframework.context.annotation.DependsOn;
import org.springframework.context.annotation.Primary;

import javax.sql.DataSource;
import java.io.File;

/**
 * Inicia o MariaDB embutido (MySQL-compatível) automaticamente ao subir a aplicação.
 * O banco de dados é armazenado em ~/.myfinance/db — o usuário NÃO precisa instalar o MySQL.
 * Funciona em Windows 64-bit e Ubuntu (Linux x86_64).
 *
 * Para desabilitar (ex.: durante testes), configure:
 *   app.database.embedded=false
 */
@Configuration
@ConditionalOnProperty(name = "app.database.embedded", havingValue = "true", matchIfMissing = false)
public class EmbeddedDatabaseConfig {

    @Value("${app.database.port:13306}")
    private int port;

    @Value("${app.database.name:controle_financeiro}")
    private String dbName;

    /**
     * Inicia o servidor MariaDB embutido e cria o schema se ainda não existir.
     * Os dados ficam em: <usuario>/.myfinance/db
     */
    @Bean(destroyMethod = "stop")
    public DB embeddedMariaDB() throws ManagedProcessException {
        String dataDir = System.getProperty("user.home")
                + File.separator + ".myfinance"
                + File.separator + "db";

        DBConfigurationBuilder config = DBConfigurationBuilder.newBuilder();
        config.setPort(port);
        config.setDataDir(new File(dataDir));

        DB db = DB.newEmbeddedDB(config.build());
        db.start();

        // Cria o banco de dados se ainda não existir (seguro chamar múltiplas vezes)
        try {
            db.createDB(dbName);
        } catch (ManagedProcessException e) {
            // Banco já existe — comportamento esperado após a primeira execução
            System.out.println("[EmbeddedDB] Banco '" + dbName + "' já existente, continuando...");
        }

        System.out.println("[EmbeddedDB] MariaDB iniciado na porta " + port + " | dados em: " + dataDir);
        return db;
    }

    /**
     * DataSource configurado para apontar ao MariaDB embutido.
     * O @DependsOn garante que o servidor já está rodando antes de conectar.
     */
    @Bean
    @Primary
    @DependsOn("embeddedMariaDB")
    public DataSource dataSource() {
        HikariDataSource ds = new HikariDataSource();
        ds.setJdbcUrl("jdbc:mysql://localhost:" + port + "/" + dbName
                + "?useSSL=false&allowPublicKeyRetrieval=true"
                + "&serverTimezone=America/Sao_Paulo"
                + "&characterEncoding=UTF-8");
        ds.setUsername("root");
        ds.setPassword("");
        ds.setDriverClassName("com.mysql.cj.jdbc.Driver");
        ds.setMaximumPoolSize(10);
        ds.setMinimumIdle(2);
        ds.setConnectionTimeout(30000);
        return ds;
    }
}

package controle.api.back_end.config;

import ch.vorburger.exec.ManagedProcessException;
import ch.vorburger.mariadb4j.DB;
import ch.vorburger.mariadb4j.DBConfiguration;
import ch.vorburger.mariadb4j.DBConfigurationBuilder;
import com.zaxxer.hikari.HikariDataSource;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.boot.autoconfigure.condition.ConditionalOnProperty;
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import org.springframework.context.annotation.DependsOn;
import org.springframework.context.annotation.Primary;

import javax.sql.DataSource;
import java.io.File;

/**
 * Inicia o MariaDB embutido (MySQL-compatível) automaticamente ao subir a aplicação.
 * O banco de dados é armazenado em ~/.myfinance/db.
 * Funciona em Windows 64-bit e Ubuntu (Linux x86_64).
 */
@Configuration
@ConditionalOnProperty(name = "app.database.embedded", havingValue = "true", matchIfMissing = false)
public class EmbeddedDatabaseConfig {

    @Value("${app.database.port:13306}")
    private int port;

    @Value("${app.database.name:controle_financeiro}")
    private String dbName;

    /**
     * Subclasse de DB que reutiliza uma instalação MariaDB existente.
     * Chama prepareDirectories() e unpackEmbeddedDb() (ambos protected),
     * mas OMITE o install() (mysql_install_db) que falha se o datadir não estiver vazio.
     */
    private static class ExistingMariaDBInstance extends DB {
        protected ExistingMariaDBInstance(DBConfiguration config) throws ManagedProcessException {
            super(config);
            prepareDirectories(); // inicializa baseDir, libDir, tmpDir, dataDir
            unpackEmbeddedDb();   // extrai binários do JAR para o tempDir (necessário após reboot)
        }
    }

    @Bean(destroyMethod = "stop")
    public DB embeddedMariaDB() throws ManagedProcessException {
        File dataDir = new File(
                System.getProperty("user.home"),
                ".myfinance" + File.separator + "db"
        );

        DBConfigurationBuilder config = DBConfigurationBuilder.newBuilder();
        config.setPort(port);
        config.setDataDir(dataDir);

        // A pasta "mysql/" indica instalação MariaDB ja concluída.
        // Se existir: apenas inicia o servidor (pula mysql_install_db).
        // Se não existir ou estiver corrompida: limpa e faz instalação completa.
        boolean alreadyInstalled = new File(dataDir, "mysql").isDirectory();

        DB db;
        if (alreadyInstalled) {
            System.out.println("[EmbeddedDB] Banco existente detectado em: " + dataDir.getAbsolutePath());
            db = new ExistingMariaDBInstance(config.build());
        } else {
            // Diretório parcialmente corrompido ou primeira execução
            if (dataDir.exists() && dataDir.list() != null && dataDir.list().length > 0) {
                System.out.println("[EmbeddedDB] Diretório com dados incompletos detectado. Limpando para reinstalar...");
                deleteDirectoryContents(dataDir);
            }
            System.out.println("[EmbeddedDB] Primeiro inicio — instalando banco em: " + dataDir.getAbsolutePath());
            db = DB.newEmbeddedDB(config.build());
        }

        db.start();

        // Cria o schema se ainda não existir (idempotente)
        try {
            db.createDB(dbName);
        } catch (ManagedProcessException e) {
            System.out.println("[EmbeddedDB] Schema '" + dbName + "' já existente.");
        }

        System.out.println("[EmbeddedDB] MariaDB pronto na porta " + port);
        return db;
    }

    private static void deleteDirectoryContents(File dir) {
        File[] files = dir.listFiles();
        if (files != null) {
            for (File f : files) {
                if (f.isDirectory()) {
                    deleteDirectoryContents(f);
                }
                f.delete();
            }
        }
    }

    @Bean
    @Primary
    @DependsOn("embeddedMariaDB")
    public DataSource dataSource() {
        HikariDataSource ds = new HikariDataSource();
        ds.setJdbcUrl("jdbc:mariadb://localhost:" + port + "/" + dbName
                + "?useSSL=false&allowPublicKeyRetrieval=true"
                + "&serverTimezone=America/Sao_Paulo"
                + "&characterEncoding=UTF-8");
        ds.setUsername("root");
        ds.setPassword("");
        ds.setDriverClassName("org.mariadb.jdbc.Driver");
        ds.setMaximumPoolSize(10);
        ds.setMinimumIdle(2);
        ds.setConnectionTimeout(30000);
        return ds;
    }
}

package controle.api.back_end.model.categoria;


import controle.api.back_end.model.usuario.Usuario;
import jakarta.persistence.*;
import jakarta.validation.constraints.NotBlank;
import jakarta.validation.constraints.NotNull;
import jakarta.validation.constraints.Size;

import java.util.UUID;

@Entity
    public class Categoria {
        @Id
        @GeneratedValue(strategy = GenerationType.IDENTITY)
        private Integer id;

        @NotBlank
        @Size(max = 30)
        private String titulo;


    public Categoria() {
    }

    public Categoria(Integer id, String titulo) {
        this.id = id;
        this.titulo = titulo;
    }

    public Integer getId() {
        return id;
    }

    public void setId(Integer id) {
        this.id = id;
    }

    public String getTitulo() {
        return titulo;
    }

    public void setTitulo(String titulo) {
        this.titulo = titulo;
    }

}

package controle.api.back_end.model.categoria;


import controle.api.back_end.model.usuario.Usuario;
import jakarta.persistence.*;
import jakarta.validation.constraints.NotBlank;
import jakarta.validation.constraints.NotNull;
import jakarta.validation.constraints.Size;

import java.util.UUID;

@Entity
    public class Categoria {
        @Id
        @GeneratedValue(strategy = GenerationType.IDENTITY)
        private Integer id;

        @NotBlank
        @Size(max = 30)
        @Column(unique = true)
        private String titulo;


    public Categoria() {
    }

    public Categoria(Integer id, String titulo) {
        this.id = id;
        this.titulo = titulo;
    }

    public Integer getId() {
        return id;
    }

    public void setId(Integer id) {
        this.id = id;
    }

    public String getTitulo() {
        return titulo;
    }

    public void setTitulo(String titulo) {
        this.titulo = titulo;
    }

}

package controle.api.back_end.model.instituicao;

import jakarta.persistence.Entity;
import jakarta.persistence.GeneratedValue;
import jakarta.persistence.GenerationType;
import jakarta.persistence.Id;
import jakarta.validation.constraints.NotBlank;
import jakarta.validation.constraints.Size;

@Entity
public class Instituicao {
    @Id
    @GeneratedValue(strategy = GenerationType.IDENTITY)
    private Integer id;

    @Size(max = 50)
    @NotBlank
    private String nome;

    public Instituicao() {
    }

    public Instituicao(Integer id, String nome) {
        this.id = id;
        this.nome = nome;
    }

    public Integer getId() {
        return id;
    }

    public void setId(Integer id) {
        this.id = id;
    }

    public String getNome() {
        return nome;
    }

    public void setNome(String nome) {
        this.nome = nome;
    }
}

package controle.api.back_end.model.instituicao;

import jakarta.persistence.Column;
import jakarta.persistence.Entity;
import jakarta.persistence.GeneratedValue;
import jakarta.persistence.GenerationType;
import jakarta.persistence.Id;
import jakarta.validation.constraints.NotBlank;
import jakarta.validation.constraints.Size;

@Entity
public class Instituicao {
    @Id
    @GeneratedValue(strategy = GenerationType.IDENTITY)
    private Integer id;

    @Size(max = 50)
    @NotBlank
    @Column(unique = true)
    private String nome;

    public Instituicao() {
    }

    public Instituicao(Integer id, String nome) {
        this.id = id;
        this.nome = nome;
    }

    public Integer getId() {
        return id;
    }

    public void setId(Integer id) {
        this.id = id;
    }

    public String getNome() {
        return nome;
    }

    public void setNome(String nome) {
        this.nome = nome;
    }
}

